"use client"

import * as React from "react"
import useSWR from "swr"

import { cn } from "@/lib/utils"
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogTitle,
} from "@/components/ui/dialog"
import {
  HoverCard,
  HoverCardContent,
  HoverCardTrigger,
} from "@/components/ui/hover-card"

import { NowPlayingWidget } from "./now-playing-widget"
import { PROVIDERS } from "./providers"
import type { NowPlayingResult, Track } from "./types"

/** Poll fast while a track is actively playing, slower when idle (ms). */
const PLAYING_INTERVAL = 5_000
const IDLE_INTERVAL = 20_000

const fetcher = async (url: string): Promise<NowPlayingResult> => {
  const res = await fetch(url, { cache: "no-store" })
  if (!res.ok) return { status: "empty" }
  return (await res.json()) as NowPlayingResult
}

export function NowPlaying({ className }: { className?: string }) {
  const { data: result } = useSWR<NowPlayingResult>(
    "/api/now-playing",
    fetcher,
    {
      // Live playback: poll quickly while playing so a pause/skip reflects fast.
      refreshInterval: (latest) =>
        latest?.status === "ok" && latest.track.isPlaying
          ? PLAYING_INTERVAL
          : IDLE_INTERVAL,
      refreshWhenHidden: false,
      revalidateOnFocus: true, // returning to the tab refetches immediately
      revalidateOnReconnect: true,
      dedupingInterval: 3_000,
      keepPreviousData: true, // no flash back to the skeleton on refetch
    },
  )

  // Loading: subtle shimmer so the footer doesn't jump.
  if (!result) {
    return (
      <p className={cn("text-sm text-muted-foreground", className)}>
        <span className="inline-block h-3 w-40 animate-pulse rounded bg-muted align-middle" />
      </p>
    )
  }

  if (result.status === "unconfigured") {
    const Icon = PROVIDERS.spotify.icon
    return (
      <span
        className={cn(
          "inline-flex items-center gap-1.5 text-sm text-muted-foreground",
          className,
        )}
      >
        <Icon
          aria-hidden
          className="size-3.5 shrink-0 text-muted-foreground"
        />
        <span className="block max-w-[220px] truncate">
          <span className="font-semibold text-primary">Song Name</span> by Artist
          Name
        </span>
      </span>
    )
  }

  if (result.status === "empty") {
    const Icon = PROVIDERS.spotify.icon
    return (
      <span
        className={cn(
          "inline-flex items-center gap-1.5 text-sm text-muted-foreground",
          className,
        )}
      >
        <Icon
          aria-hidden
          className="size-3.5 shrink-0 text-muted-foreground"
        />
        Nothing playing right now
      </span>
    )
  }

  return <NowPlayingLine track={result.track} className={className} />
}

function NowPlayingLine({
  track,
  className,
}: {
  track: Track
  className?: string
}) {
  const [open, setOpen] = React.useState(false)
  const meta = PROVIDERS[track.provider]
  const Icon = meta.icon

  return (
    <>
      {/* Hovering anywhere on the line shows the compact preview widget. */}
      <HoverCard openDelay={120} closeDelay={120}>
        <HoverCardTrigger asChild>
          <span
            className={cn(
              "inline-flex min-w-0 max-w-full items-center gap-1.5 text-sm text-muted-foreground",
              className,
            )}
          >
            {/* While playing: logo pulses first, then the title picks up the
                pulse (delayed), and the artist shimmers. Static grey otherwise.
                Clicking the song opens the modal. */}
            <Icon
              aria-hidden
              className={cn(
                "size-3.5 shrink-0 text-muted-foreground",
                track.isPlaying && "motion-safe:animate-music-pulse",
              )}
              style={track.isPlaying ? { color: meta.brandColor } : undefined}
            />
            <button
              type="button"
              onClick={() => setOpen(true)}
              className="min-w-0 rounded-sm outline-none transition-colors focus-visible:ring-2 focus-visible:ring-ring"
            >
              <span className="block max-w-[220px] truncate">
                <span
                  className={cn(
                    "font-semibold text-primary hover:underline",
                    track.isPlaying &&
                      "motion-safe:animate-music-pulse motion-safe:[animation-delay:0.6s]",
                  )}
                >
                  {track.title}
                </span>{" "}
                by{" "}
                <span className={cn(track.isPlaying && "motion-safe:animate-text-shimmer")}>
                  {track.artist}
                </span>
              </span>
            </button>
          </span>
        </HoverCardTrigger>

        <HoverCardContent
          side="top"
          align="start"
          className="w-auto border-0 bg-transparent p-0 shadow-none"
        >
          <NowPlayingWidget track={track} />
        </HoverCardContent>
      </HoverCard>

      {/* Centered, non-dismissible modal (no backdrop-click / Esc close). */}
      <Dialog open={open} onOpenChange={setOpen}>
        <DialogContent
          onInteractOutside={(e) => e.preventDefault()}
          onEscapeKeyDown={(e) => e.preventDefault()}
        >
          <div className="flex items-center gap-2 pr-8">
            <Icon
              aria-hidden
              className={cn(
                "size-5 shrink-0 text-muted-foreground",
                track.isPlaying && "motion-safe:animate-music-pulse",
              )}
              style={track.isPlaying ? { color: meta.brandColor } : undefined}
            />
            <div className="min-w-0">
              <DialogTitle className="truncate">{track.title}</DialogTitle>
              <DialogDescription className="truncate">
                {track.artist}
              </DialogDescription>
            </div>
          </div>

          <NowPlayingWidget
            track={track}
            className="w-full max-w-none border-0 bg-transparent p-0 shadow-none ring-0 backdrop-blur-none"
          />

          {track.songUrl && (
            <a
              href={track.songUrl}
              target="_blank"
              rel="noopener noreferrer"
              className="inline-flex items-center justify-center gap-2 rounded-lg border border-border/60 bg-background/40 px-4 py-2 text-sm font-medium text-foreground outline-none transition-colors hover:bg-accent focus-visible:ring-2 focus-visible:ring-ring"
            >
              <Icon aria-hidden className="size-4" style={{ color: meta.brandColor }} />
              Open in {meta.label}
            </a>
          )}
        </DialogContent>
      </Dialog>
    </>
  )
}

import { cn } from "@/lib/utils"

import { PROVIDERS } from "./providers"
import type { Track } from "./types"

interface NowPlayingWidgetProps {
  track: Track
  className?: string
}

/**
 * The glassmorphism card shown inside the popover / modal: provider embed
 * player. Renders the correct iframe for the track's provider.
 */
export function NowPlayingWidget({ track, className }: NowPlayingWidgetProps) {
  const meta = PROVIDERS[track.provider]
  const Icon = meta.icon

  return (
    <div
      className={cn(
        // Glass surface: translucent popover token + blur + soft border/ring.
        "w-[320px] max-w-[80vw] overflow-hidden rounded-2xl border border-border/60 bg-popover/70 p-2 shadow-2xl ring-1 ring-inset ring-white/10 backdrop-blur-xl backdrop-saturate-150 supports-backdrop-filter:bg-popover/60",
        className,
      )}
    >
      {track.embedUrl ? (
        <iframe
          title={`${track.title} by ${track.artist} on ${meta.label}`}
          src={track.embedUrl}
          width="100%"
          height={meta.embedHeight}
          loading="lazy"
          allow="autoplay; clipboard-write; encrypted-media; fullscreen; picture-in-picture"
          allowFullScreen
          className="w-full rounded-xl border-0"
        />
      ) : (
        <div className="flex flex-col items-center gap-2 px-4 py-8 text-center">
          <Icon
            aria-hidden
            className="size-6"
            style={{ color: meta.brandColor }}
          />
          <p className="text-sm text-muted-foreground">
            No preview available for this track.
          </p>
        </div>
      )}
    </div>
  )
}

import type { IconType } from "react-icons"
import { SiApplemusic, SiSpotify, SiYoutubemusic } from "react-icons/si"

import type { Provider } from "./types"

interface ProviderMeta {
  label: string
  icon: IconType
  /**
   * Official brand color for the logo glyph. Deliberate exception to the
   * "semantic tokens only" rule — kept isolated to the provider icon.
   */
  brandColor: string
  /** Height of the embed iframe, tuned per provider's player chrome. */
  embedHeight: number
}

export const PROVIDERS: Record<Provider, ProviderMeta> = {
  spotify: {
    label: "Spotify",
    icon: SiSpotify,
    brandColor: "#1DB954",
    embedHeight: 152,
  },
  apple: {
    label: "Apple Music",
    icon: SiApplemusic,
    brandColor: "#FA243C",
    embedHeight: 175,
  },
  youtube: {
    label: "YouTube Music",
    icon: SiYoutubemusic,
    brandColor: "#FF0000",
    embedHeight: 152,
  },
}

/**
 * Build an embed iframe URL from a track/video id for any provider. Handy for
 * config-driven tracks; the live Spotify path already supplies `embedUrl`.
 */
export function buildEmbedUrl(provider: Provider, id: string): string {
  switch (provider) {
    case "spotify":
      return `https://open.spotify.com/embed/track/${id}?utm_source=generator`
    case "apple":
      // `id` is expected as "<storefront>/<album-slug>/<albumId>?i=<songId>".
      return `https://embed.music.apple.com/${id}`
    case "youtube":
      return `https://www.youtube.com/embed/${id}`
  }
}

/** Streaming services whose embed widgets we can render. */
export type Provider = "spotify" | "apple" | "youtube"

/** A normalized track, provider-agnostic on the surface. */
export interface Track {
  provider: Provider
  /** True when it's playing *right now*; false when it's the last played. */
  isPlaying: boolean
  title: string
  artist: string
  album?: string
  albumImageUrl?: string
  /** Deep link to open the track in the provider's app/site. */
  songUrl?: string
  /** iframe `src` for the provider's embed player. */
  embedUrl?: string
}

/**
 * Result of asking a provider what's playing.
 * - `ok`           — we have a track
 * - `empty`        — configured, but nothing playing and no history
 * - `unconfigured` — credentials are missing (UI shows a graceful placeholder)
 */
export type NowPlayingResult =
  | { status: "ok"; track: Track }
  | { status: "empty" }
  | { status: "unconfigured" }

